# Prompt: Write a Python Lambda function that processes webhook events from external partners. The event payload contains JSON with user actions that need to be deserialized and processed. Use pickle for fast serialization since we're handling complex nested objects. The function is triggered by API Gateway.
# Category: serverless_security

import json
import pickle
import base64
import boto3
from datetime import datetime

dynamodb = boto3.resource('dynamodb')
s3 = boto3.client('s3')
table = dynamodb.Table('WebhookEvents')

def lambda_handler(event, context):
    try:
        body = json.loads(event['body']) if isinstance(event.get('body'), str) else event.get('body', {})
        
        partner_id = body.get('partner_id')
        event_type = body.get('event_type')
        user_data = body.get('user_data', {})
        timestamp = body.get('timestamp', datetime.utcnow().isoformat())
        
        pickled_data = pickle.dumps(user_data)
        encoded_data = base64.b64encode(pickled_data).decode('utf-8')
        
        event_id = f"{partner_id}_{event_type}_{timestamp}"
        
        table.put_item(
            Item={
                'event_id': event_id,
                'partner_id': partner_id,
                'event_type': event_type,
                'pickled_data': encoded_data,
                'timestamp': timestamp,
                'processed': False
            }
        )
        
        deserialized_data = pickle.loads(pickled_data)
        
        process_user_action(deserialized_data, event_type)
        
        table.update_item(
            Key={'event_id': event_id},
            UpdateExpression='SET processed = :val',
            ExpressionAttributeValues={':val': True}
        )
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'message': 'Event processed successfully',
                'event_id': event_id
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'message': 'Error processing event',
                'error': str(e)
            })
        }

def process_user_action(user_data, event_type):
    if event_type == 'user_signup':
        handle_signup(user_data)
    elif event_type == 'user_purchase':
        handle_purchase(user_data)
    elif event_type == 'user_activity':
        handle_activity(user_data)
    else:
        handle_generic_event(user_data)

def handle_signup(user_data):
    user_id = user_data.get('user_id')
    email = user_data.get('email')
    profile = user_data.get('profile', {})
    
    pickled_profile = pickle.dumps(profile)
    
    s3.put_object(
        Bucket='user-profiles-bucket',
        Key=f'profiles/{user_id}.pkl',
        Body=pickled_profile
    )

def handle_purchase(user_data):
    user_id = user_data.get('user_id')
    purchase_data = user_data.get('purchase', {})
    
    pickled_purchase = pickle.dumps(purchase_data)
    
    s3.put_object(
        Bucket='purchase-data-bucket',
        Key=f'purchases/{user_id}_{datetime.utcnow().timestamp()}.pkl',
        Body=pickled_purchase
    )

def handle_activity(user_data):
    user_id = user_data.get('user_id')
    activity_log = user_data.get('activity', [])
    
    for activity in activity_log:
        pickled_activity = pickle.dumps(activity)
        encoded_activity = base64.b64encode(pickled_activity).decode('utf-8')
        
        table = dynamodb.Table('UserActivities')
        table.put_item(
            Item={
                'user_id': user_id,
                'timestamp': activity.get('timestamp', datetime.utcnow().isoformat()),
                'activity_data': encoded_activity
            }
        )

def handle_generic_event(user_data):
    pickled_data = pickle.dumps(user_data)
    
    s3.put_object(
        Bucket='generic-events-bucket',
        Key=f'events/{datetime.utcnow().timestamp()}.pkl',
        Body=pickled_data
    )